const today = $('Set Today').first().json.today;
const dayOfWeek = new Date(today + 'T18:00:00Z').toLocaleDateString('en-US', { weekday: 'long', timeZone: 'America/Chicago' });

let mtl = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  mtl = buf.toString('utf-8');
} catch(e) {}

// Tasks due today or overdue
const tasksDue = [];
const reTask = /^- \[ \] .+?\[due:: (\d{4}-\d{2}-\d{2})\]/gm;
let m;
while ((m = reTask.exec(mtl)) !== null) {
  if (m[1] <= today) tasksDue.push(m[0]);
}

// Priority A rocks without a due date — the needle-movers
const rocksA = [];
const reRock = /^- \[ \] (.+?)\[area:: ([^\]]+)\].*?\[priority:: A\](?!.*\[due::)/gm;
let r;
while ((r = reRock.exec(mtl)) !== null) {
  rocksA.push(`- [ ] ${r[1].trim()} [area:: ${r[2]}] [priority:: A]`);
}

const dueLine = tasksDue.length > 0
  ? tasksDue.join('\n')
  : '*No tasks due today — great time to advance a Rock.*';

const rocksLine = rocksA.length > 0
  ? rocksA.slice(0, 5).join('\n')
  : '*No undated Priority A rocks found.*';

const note = `---
date: ${today}
day: ${dayOfWeek}
type: daily-note
---

# ${dayOfWeek}, ${today}

## 🎯 Today's ONE Thing
<!-- The single most important thing to accomplish today -->

## ⚡ Tasks Due Today (${tasksDue.length})
${dueLine}

## 🪨 Priority A Rocks — Keep Moving These Forward
${rocksLine}

## 📝 Notes & Brain Dump
<!-- Capture thoughts throughout the day -->

## 🔍 End of Day Review
- [ ] Did I move a Quarterly Rock forward?
- [ ] What went well?
- [ ] What would I do differently?
- [ ] Anything to capture for tomorrow?

---
*Auto-generated at ${new Date().toISOString()} — ${tasksDue.length} tasks due, ${rocksA.length} A-rocks active*
`;

return [{ json: { key: `40_Timeline_Weekly/Daily/${today}.md`, content: note, today, taskCount: tasksDue.length, rockCount: rocksA.length } }];

// Convert markdown content to binary for S3 upload
const content = $json.content;
const key = $json.key;
const fileName = key.split('/').pop();
const buf = Buffer.from(content, 'utf-8');
return [{ json: $json, binary: { data: { data: buf.toString('base64'), mimeType: 'text/markdown; charset=utf-8', fileName: fileName, fileExtension: 'md', fileSize: buf.length } } }];

// Write run log to MinIO
const today = $('Set Today').first().json.today;
const log = {
  workflow: 'daily-note-creator-v2',
  date: today,
  status: 'success',
  taskCount: $json.taskCount,
  rockCount: $json.rockCount,
  key: $json.key,
  ts: new Date().toISOString()
};
const buf = Buffer.from(JSON.stringify(log, null, 2), 'utf-8');
return [{ json: { logKey: `99_System/logs/daily-note-creator-${today}.json`, ...log }, binary: { logFile: { data: buf.toString('base64'), mimeType: 'application/json', fileName: `daily-note-creator-${today}.json`, fileExtension: 'json', fileSize: buf.length } } }];
